using System.ComponentModel;
using System.Drawing;
using System.Runtime.InteropServices;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private StatusStrip _statusStrip;
    private ToolStripStatusLabel _statusLabel;

    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        _statusLabel = new ToolStripStatusLabel("Ready");

        // .NET 9: StatusStrip no longer defaults to
        // ToolStripProfessionalRenderer. Explicitly set it to preserve
        // the .NET 8 visual appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        ToolStripManager.Renderer = new ToolStripProfessionalRenderer();

        _statusStrip.Items.Add(_statusLabel);
        Controls.Add(_statusStrip);
    }
}

public class SafeDropDownEditor
{
    // .NET 9: DropDownControl now throws ArgumentNullException when
    // passed null. Guard against it.
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        ArgumentNullException.ThrowIfNull(control);
        editorService.DropDownControl(control);
    }
}

